"""
T3 E-commerce — Product Routes (Sample 2: Functional Style Variant)

Design decisions for this variant:
1. Functional serialization helper instead of inline dict construction
2. Explicit validation function with field-level error messages
3. Use 201 Created for successful POST (vs 200 OK)
4. Separate concerns: validation -> authorization -> execution
5. Use a tuple-based internal response pattern (status_code, payload)
   to decouple business logic from HTTP response formatting
"""

from flask import Blueprint, request, jsonify
import sys
import os
sys.path.insert(0, os.path.dirname(__file__))

from models import Product
from middleware import get_current_user

product_bp = Blueprint('product_bp', __name__)

# --- Product serialization ---

PRODUCT_FIELDS = ('id', 'name', 'price', 'stock')


def serialize_product(product):
    """Serialize a Product instance using a fixed field whitelist.
    This avoids modifying models.py while keeping serialization centralized."""
    return {field: getattr(product, field) for field in PRODUCT_FIELDS}


def serialize_products(products):
    """Serialize a list of Product instances."""
    return [serialize_product(p) for p in products]


# --- Request validation ---

REQUIRED_CREATE_FIELDS = {
    'name': str,
    'price': (int, float),
    'stock': int,
}


def validate_create_payload(data):
    """Validate POST /products request body.
    Returns (errors, validated_data).
    - errors: list of error strings, empty if valid.
    - validated_data: dict with coerced values, or None if invalid.
    """
    if not data:
        return ['Request body is required'], None

    errors = []
    validated = {}

    for field, expected_type in REQUIRED_CREATE_FIELDS.items():
        if field not in data:
            errors.append(f'Missing required field: {field}')
            continue

        value = data[field]
        if not isinstance(value, expected_type):
            actual = type(value).__name__
            allowed = (
                expected_type.__name__
                if isinstance(expected_type, type)
                else ' or '.join(t.__name__ for t in expected_type)
            )
            errors.append(
                f'Field "{field}" expects {allowed}, got {actual}'
            )
            continue

        # Coerce int/float for price
        if field == 'price' and isinstance(value, int):
            value = float(value)

        validated[field] = value

    if errors:
        return errors, None

    # Business rule: price and stock must be non-negative
    if validated['price'] < 0:
        errors.append('price must be non-negative')
    if validated['stock'] < 0:
        errors.append('stock must be non-negative')

    if errors:
        return errors, None

    return [], validated


# --- Routes ---

@product_bp.route('/products', methods=['GET'])
def list_products():
    """List all products. No authentication required."""
    products = Product.query.all()
    return jsonify({
        'status': 'ok',
        'data': serialize_products(products),
    }), 200


@product_bp.route('/products', methods=['POST'])
def create_product():
    """Create a new product. Admin only.
    Returns 401 if no user, 403 if not admin, 422 if validation fails,
    201 on success.
    """
    # Step 1: Authentication check
    current_user = get_current_user()
    if current_user is None:
        return jsonify({
            'status': 'error',
            'message': 'Authentication required. Provide X-User-Id header.',
        }), 401

    # Step 2: Authorization check
    if current_user.role != 'admin':
        return jsonify({
            'status': 'error',
            'message': 'Forbidden. Admin role required.',
        }), 403

    # Step 3: Payload validation
    errors, validated = validate_create_payload(request.get_json(silent=True))
    if errors:
        return jsonify({
            'status': 'error',
            'errors': errors,
        }), 422

    # Step 4: Create and persist
    product = Product(
        name=validated['name'],
        price=validated['price'],
        stock=validated['stock'],
    )
    from app import db
    db.session.add(product)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': serialize_product(product),
    }), 201

